-- ============================================================================
-- V13 - Melee catalog (generated from src/main/resources/catalog/*.json)
-- ============================================================================
-- Adds the Unity Melee catalog on top of the Vandal set from V12: upserts the
-- Melee skins as active and adds the melee_case with its drop pool. Does not
-- touch the existing Vandal skins or cases. Catalog tables only; no player-owned
-- tables are referenced.
-- ============================================================================

-- Melee skins (168). Upsert by primary key id.
ON CONFLICT (id) DO UPDATE SET
    display_name = EXCLUDED.display_name,
    weapon       = EXCLUDED.weapon,
    rarity       = EXCLUDED.rarity,
    vp_value     = EXCLUDED.vp_value,
    image_ref    = EXCLUDED.image_ref,
    active       = EXCLUDED.active;

-- Melee case. Upsert by primary key id.
ON CONFLICT (id) DO UPDATE SET
    display_name = EXCLUDED.display_name,
    price_vp     = EXCLUDED.price_vp,
    image_ref    = EXCLUDED.image_ref,
    active       = EXCLUDED.active;

-- Rebuild melee_case drop pool: drop its entries, then insert the current pool.
DELETE FROM case_entries WHERE case_id = 'melee_case';

-- Melee drop-pool entries (15).
